function goAnchor(obj, hash) {
    if (hash.length == 0) {
        return
    }
    //获取元素
let anchor = obj.$el.querySelector(hash);
if(anchor) {
    // setTimeout( () => {
    //页面没有渲染完成时是无法滚动的，因此设置延迟
    //js的内置方法，可滚动视图位置至元素位置
        anchor.scrollIntoView();
    // },100);
  }
} 

export { goAnchor };


